    def _nearest_camera_fixture(self, eid, pos):
        nearby = self.sim.properties_in_radius(pos.x, pos.y, pos.z, r=1)
        candidates = []
        for prop in nearby:
            if _property_infrastructure_role(prop) != "camera_target":
                continue
            candidates.append((
                self._interaction_target_sort_key(
                    eid,
                    pos,
                    int(prop.get("x", 0)),
                    int(prop.get("y", 0)),
                    stable_tiebreaker=(str(prop.get("id", "")),),
                ),
                prop,
            ))
        if not candidates:
            return None
        candidates.sort(key=lambda row: row[0])
        return candidates[0][1]

    def _player_disable_camera(self, eid, pos, prop):
        now = self.sim.tick
        prop_id = prop["id"]
        cam_name = prop.get("name", "camera")
        cam_disabled = getattr(self.sim, "camera_disabled", None)
        if not isinstance(cam_disabled, dict):
            self.sim.camera_disabled = {}
            cam_disabled = self.sim.camera_disabled
        if cam_disabled.get(prop_id, 0) > now:
            _log_player_feedback(
                self.sim,
                f"The {cam_name} is already blind.",
                kind="interaction",
            )
            return
        _emit_action_offense_event(
            self.sim,
            eid=eid,
            action="interact",
            context="tamper",
            x=int(pos.x),
            y=int(pos.y),
            z=int(pos.z),
        )
        duration = 120 + (int(self.sim.seed or 0) % 30)
        cam_disabled[prop_id] = now + duration
        target_prop = self._security_fixture_target_property(prop)
        target_name = str((target_prop or {}).get("name", "")).strip()
        _log_player_feedback(
            self.sim,
            (
                f"You blind the {cam_name}. Surveillance at {target_name} is thinner."
            )
            if target_name
            else f"You blind the {cam_name}. Nearby surveillance is thinner.",
            kind="interaction",
        )
        self.sim.emit(Event(
            "camera_disabled",
            eid=eid,
            property_id=prop_id,
            disabled_until=now + duration,
        ))

